## vite.config.ts Patterns

```ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react-swc';  // SWC for fast HMR
import path from 'node:path';

export default defineConfig({
  plugins: [react()],

  // Path aliases — keep in sync with tsconfig.json paths
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
      '@ui': path.resolve(__dirname, './src/components/ui'),
      '@lib': path.resolve(__dirname, './src/lib'),
    },
  },

  // Only expose vars prefixed with VITE_ to client
  envPrefix: 'VITE_',

  // Dev server proxy — avoids CORS in development
  server: {
    port: 3000,
    proxy: {
      '/api': {
        target: 'http://localhost:4000',
        changeOrigin: true,
        rewrite: (path) => path.replace(/^\/api/, ''),
      },
    },
  },

  // Build output
  build: {
    outDir: 'dist',
    sourcemap: true,  // always; strip in CI with sourcemap:false for prod
    target: 'es2020',
  },

  // Align with tsconfig.json paths
  // tsconfig.json: { "paths": { "@/*": ["./src/*"] } }
});
```

## Code Splitting in Vite

### Route-based lazy loading (React Router / TanStack Router)
```tsx
import { lazy, Suspense } from 'react';

// Each route = separate chunk, loaded on navigation
const Dashboard  = lazy(() => import('./pages/Dashboard'));
const Analytics  = lazy(() => import('./pages/Analytics'));
const Settings   = lazy(() => import('./pages/Settings'));

function App() {
  return (
    <Suspense fallback={<PageSkeleton />}>
      <Routes>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/analytics" element={<Analytics />} />
      </Routes>
    </Suspense>
  );
}
```

### Manual chunks (vendor splitting)
```ts
// vite.config.ts
build: {
  rollupOptions: {
    output: {
      manualChunks: {
        // Stable vendor chunks — long-term browser cache
        'vendor-react': ['react', 'react-dom'],
        'vendor-query': ['@tanstack/react-query'],
        'vendor-ui':    ['@radix-ui/react-dialog', '@radix-ui/react-tooltip'],
        'vendor-charts': ['recharts'],
      },
    },
  },
}
```

### Lazy-load heavy components
```tsx
// Only load chart library when the chart page is visited
const ChartComponent = lazy(() =>
  import('recharts').then(m => ({ default: m.LineChart }))
);

// Lazy-load after user interaction
async function openEditor() {
  const { Editor } = await import('./components/RichTextEditor');
  setEditorComponent(() => Editor);
}
```

**Rule:** Initial bundle should be < 150KB gzipped. Every route-group gets its own chunk.

## Vite Environment Variables

### File hierarchy (Vite loads in order, later wins)
```
.env               # always loaded (base)
.env.local         # always loaded, gitignored
.env.development   # only in dev (npm run dev)
.env.production    # only in build (npm run build)
.env.test          # only in test mode
```

### Access in code
```ts
// ONLY vars prefixed VITE_ are exposed to client code
import.meta.env.VITE_API_URL     // your custom var
import.meta.env.MODE             // 'development' | 'production' | 'test'
import.meta.env.PROD             // boolean
import.meta.env.DEV              // boolean
import.meta.env.BASE_URL         // base URL from config.base
```

### Type-safe env vars (src/env.d.ts)
```ts
/// <reference types="vite/client" />

interface ImportMetaEnv {
  readonly VITE_API_URL: string;
  readonly VITE_APP_TITLE: string;
  readonly VITE_FEATURE_FLAGS: string;  // JSON string, parse at runtime
}

interface ImportMeta {
  readonly env: ImportMetaEnv;
}
```

### Validate at startup
```ts
// src/lib/env.ts — validated, typed env object
const env = {
  apiUrl:    import.meta.env.VITE_API_URL    || fail('VITE_API_URL required'),
  appTitle:  import.meta.env.VITE_APP_TITLE  || 'My App',
};

function fail(msg: string): never { throw new Error(msg); }
export { env };
```

**Security:** Never prefix secrets with `VITE_` — they are exposed in the browser bundle.

## Essential Vite Plugins

```bash
npm install -D @vitejs/plugin-react-swc  # SWC = 20× faster than Babel
npm install -D vite-plugin-svgr         # import SVG as React components
npm install -D unplugin-auto-import     # auto-import React hooks
```

```ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react-swc';
import svgr from 'vite-plugin-svgr';
import AutoImport from 'unplugin-auto-import/vite';

export default defineConfig({
  plugins: [
    react(),

    // Import SVG as React component
    svgr({ svgrOptions: { icon: true } }),
    // Usage: import Logo from './logo.svg?react';

    AutoImport({
      imports: ['react'],   // auto-import useState, useEffect, etc.
      dts: 'src/auto-imports.d.ts',
    }),
  ],
});
```

### Tailwind v4 with Vite
```bash
npm install tailwindcss @tailwindcss/vite
```
```ts
import tailwindcss from '@tailwindcss/vite';
export default defineConfig({ plugins: [react(), tailwindcss()] });
```

### Path-based CSS Modules
```ts
// Vite handles *.module.css automatically — no plugin needed
import styles from './Button.module.css';
<button className={styles.button}>...</button>

// Global styles
import './globals.css'; // not *.module.css = global scope
```

## Bundle Analysis

```bash
npm install -D rollup-plugin-visualizer
```

```ts
// vite.config.ts
import { visualizer } from 'rollup-plugin-visualizer';

export default defineConfig({
  plugins: [
    react(),
    // Generates stats.html after build
    visualizer({
      open: true,          // auto-open in browser
      gzipSize: true,      // show gzipped sizes
      brotliSize: true,
      filename: 'dist/stats.html',
    }),
  ],
});
// Run: npm run build  →  opens visual treemap of bundle
```

### Size budgets (chunkSizeWarningLimit)
```ts
build: {
  chunkSizeWarningLimit: 150,  // warn if any chunk > 150KB
  rollupOptions: {
    output: {
      manualChunks: { vendor: ['react', 'react-dom'] },
    },
  },
}
```

### Common bundle bloat patterns
```ts
// WRONG — imports entire lodash (70KB)
import _ from 'lodash';

// CORRECT — tree-shaken, only imports throttle
import throttle from 'lodash/throttle';
// Or: use native alternatives (Object.keys, Array.from, etc.)

// WRONG — imports entire date-fns
import * as dateFns from 'date-fns';

// CORRECT — named import (tree-shaken)
import { format, parseISO } from 'date-fns';
```

### Budget targets
| Chunk | Gzipped budget |
|-------|----------------|
| Initial (landing page) | < 150KB |
| App shell (auth + layout) | < 300KB |
| Per-route chunk | < 50KB |
| Vendor chunk | < 200KB (cache long-term) |
